"use client";

import { useSelector } from "react-redux";
import { RootState } from "@/redux/store";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { useTranslations } from "next-intl";

interface ProtectedRouteProps {
  children: React.ReactNode;
  requiredRole?: string | string[];
}

export default function ProtectedRoute({
  children,
  requiredRole,
}: ProtectedRouteProps) {
  const { user, token } = useSelector((state: RootState) => state.auth);
  const router = useRouter();
  const t = useTranslations("Common");

  // 1. Standard hydration fix
  const [mounted, setMounted] = useState(false);
  useEffect(() => {
    setMounted(true);
  }, []);

  // 2. Separate logic for Redirection & BFCache
  useEffect(() => {
    if (!mounted) return;

    const storedToken = localStorage.getItem("token");
    if (!token && !storedToken) {
      router.replace("/login");
    }

    const handlePageShow = (event: PageTransitionEvent) => {
      if (event.persisted) {
        window.location.reload();
      }
    };

    window.addEventListener("pageshow", handlePageShow);
    return () => window.removeEventListener("pageshow", handlePageShow);
  }, [mounted, token, router]);

  // 3. Prevent SSR mismatch
  if (!mounted) return null;

  // 4. Check for token existence (Client-side)
  const hasToken = token || (typeof window !== "undefined" && !!localStorage.getItem("token"));

  if (!hasToken) {
    return null; 
  }

  // 5. Wait for User object to be populated in Redux
  if (!user) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin h-8 w-8 border-4 border-sol-accent border-t-transparent rounded-full"></div>
      </div>
    );
  }

  // 6. Role & Permission Validation
  const userRole = user?.role?.toLowerCase();
  
  const isRoleAllowed = () => {
    if (!requiredRole) return true;
    
    const requiredRoles = Array.isArray(requiredRole) ? requiredRole : [requiredRole];
    const normalizedRequiredRoles = requiredRoles.map(r => r.toLowerCase());
    
    // Check direct role match
    if (normalizedRequiredRoles.includes(userRole)) return true;

    // Special Case: "student" role requirement
    // If 'student' is required, allow any role that has read:lesson permission
    // This allows custom student roles (like isom_student) that have been given student permissions
    if (normalizedRequiredRoles.includes("student")) {
       const permissions = user.permissions || {};
       const lessonPerms = permissions["lesson"] || [];
       if (lessonPerms.includes("read") || lessonPerms.includes("manage")) return true;
    }

    return false;
  };

  if (!isRoleAllowed()) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen text-sol-text">
        <h1 className="text-2xl font-bold text-sol-red">{t("accessDenied")}</h1>
        <p className="mt-2 text-sol-muted">
          {t("requiredFound", { 
            required: Array.isArray(requiredRole) ? requiredRole.join(", ") : (requiredRole ?? ""), 
            found: user.role ?? "" 
          })}
        </p>
        <button 
          onClick={() => router.push("/")}
          className="mt-4 px-4 py-2 bg-sol-accent text-sol-bg rounded hover:bg-sol-accent/90 transition-colors"
        >
          {t("backToHome")}
        </button>
      </div>
    );
  }

  return <>{children}</>;
}
